### SwiftUI List and Navigation

Lists display scrollable rows of data. Navigation APIs enable hierarchical navigation between views.

**List View:**

```swift
struct SimpleList: View {
    let items = ["Apple", "Banana", "Cherry", "Date"]

    var body: some View {
        List(items, id: \.self) { item in
            Text(item)
        }
    }
}

// With sections
List {
    Section("Fruits") {
        Text("Apple")
        Text("Banana")
    }
    Section("Vegetables") {
        Text("Carrot")
        Text("Broccoli")
    }
}
```

**Identifiable Protocol:**

```swift
struct Item: Identifiable {
    let id = UUID()
    let name: String
    let description: String
}

struct ItemRow: View {
    let item: Item

    var body: some View {
        VStack(alignment: .leading) {
            Text(item.name).font(.headline)
            Text(item.description).font(.caption).foregroundColor(.gray)
        }
    }
}

struct ContentView: View {
    let items = [
        Item(name: "Swift", description: "Programming language"),
        Item(name: "SwiftUI", description: "UI framework")
    ]

    var body: some View {
        List(items) { item in
            ItemRow(item: item)
        }
    }
}
```

**NavigationStack (iOS 16+):**

```swift
struct ContentView: View {
    var body: some View {
        NavigationStack {
            List(items) { item in
                NavigationLink(value: item) {
                    ItemRow(item: item)
                }
            }
            .navigationDestination(for: Item.self) { item in
                DetailView(item: item)
            }
            .navigationTitle("Items")
        }
    }
}

struct DetailView: View {
    let item: Item

    var body: some View {
        VStack {
            Text(item.name).font(.largeTitle)
            Text(item.description).font(.body)
        }
        .navigationTitle(item.name)
        .navigationBarTitleDisplayMode(.inline)
    }
}
```

**NavigationLink (iOS 15 compatible):**

```swift
NavigationView {
    List {
        NavigationLink(destination: DetailView(item: item)) {
            ItemRow(item: item)
        }
    }
    .navigationTitle("Items")
}
```

**List Operations:**

| Modifier | Description |
|----------|-------------|
| `.onDelete()` | Swipe to delete |
| `.onMove()` | Drag to reorder |
| `.refreshable()` | Pull to refresh |
| `.searchable()` | Search bar |

> **Key Point:** Use `NavigationStack` (iOS 16+) for modern navigation with type-safe routing. Use `NavigationView` for backward compatibility.

Lists support dynamic rows, swipe actions, pull-to-refresh, and search.

codeExample:
import SwiftUI

struct Book: Identifiable {
    let id = UUID()
    let title: String
    let author: String
    let year: Int
}

struct BookListView: View {
    @State private var books = [
        Book(title: "1984", author: "George Orwell", year: 1949),
        Book(title: "To Kill a Mockingbird", author: "Harper Lee", year: 1960),
        Book(title: "The Great Gatsby", author: "F. Scott Fitzgerald", year: 1925),
        Book(title: "Pride and Prejudice", author: "Jane Austen", year: 1813)
    ]
    @State private var searchText = ""

    var filteredBooks: [Book] {
        if searchText.isEmpty { return books }
        return books.filter { $0.title.localizedCaseInsensitiveContains(searchText) }
    }

    var body: some View {
        NavigationStack {
            List {
                ForEach(filteredBooks) { book in
                    NavigationLink(value: book) {
                        VStack(alignment: .leading) {
                            Text(book.title)
                                .font(.headline)
                            Text(book.author)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                }
                .onDelete { indexSet in
                    books.remove(atOffsets: indexSet)
                }
            }
            .navigationDestination(for: Book.self) { book in
                BookDetailView(book: book)
            }
            .navigationTitle("Books")
            .searchable(text: $searchText)
            .toolbar {
                EditButton()
            }
        }
    }
}

struct BookDetailView: View {
    let book: Book

    var body: some View {
        VStack(spacing: 20) {
            Text(book.title)
                .font(.largeTitle)
            Text("by \(book.author)")
                .font(.title2)
            Text("Published: \(String(book.year))")
                .font(.body)
            Spacer()
        }
        .padding()
        .navigationTitle(book.title)
        .navigationBarTitleDisplayMode(.inline)
    }
}
